/**
 * Checks if a number is prime.
 * @param num The number to check.
 * @returns True if the number is prime, false otherwise.
 */
function isPrime(num: number): boolean {
    if (num <= 1) return false;
    if (num <= 3) return true;
    if (num % 2 === 0 || num % 3 === 0) return false;
    let i = 5;
    while (i * i <= num) {
        if (num % i === 0 || num % (i + 2) === 0) return false;
        i += 6;
    }
    return true;
}

/**
 * Reverses the digits of an integer.
 * @param n The integer to reverse.
 * @returns The reversed integer.
 */
function reverseNumber(n: number): number {
    const s = String(n);
    const reversedS = s.split('').reverse().join('');
    // parseInt handles potential leading zeros correctly for the reversed number
    return parseInt(reversedS);
}

/**
 * Calculates the sum of all prime numbers between min(n, r) and max(n, r) inclusive,
 * where r is the number n with its digits reversed.
 * 
 * @param n The input integer.
 * @returns The sum of prime numbers in the range.
 */
function solve(n: number): number {
    // 1. Reverse n to get r
    const r = reverseNumber(n);

    // 2. Determine the range [start, end]
    const start = Math.min(n, r);
    const end = Math.max(n, r);

    // 3. Calculate the sum of primes in the range [start, end]
    let sumOfPrimes = 0;
    for (let i = start; i <= end; i++) {
        if (isPrime(i)) {
            sumOfPrimes += i;
        }
    }

    return sumOfPrimes;
}
